     1→//! Database schema initialization and migrations.
     2→//!
     3→//! This module contains the SQLite schema definition for the Harness storage layer.
     4→//! Key features:
     5→//! - WAL mode for better concurrency
     6→//! - FTS5 virtual tables for full-text search
     7→//! - Triggers to sync FTS5 with source tables
     8→//! - Schema versioning for migrations
     9→
    10→use rusqlite::Connection;
    11→
    12→use super::DbResult;
    13→
    14→/// Current schema version (semantic versioning).
    15→pub const SCHEMA_VERSION: &str = "1.0.0";
    16→
    17→/// SQLite pragmas to run on every connection.
    18→pub const PRAGMAS: &str = r#"
    19→PRAGMA journal_mode = WAL;
    20→PRAGMA synchronous = NORMAL;
    21→PRAGMA foreign_keys = OFF;
    22→"#;
    23→
    24→/// Core schema creation SQL.
    25→pub const SCHEMA_SQL: &str = r#"
    26→-- ============================================================================
    27→-- SCHEMA METADATA
    28→-- ============================================================================
    29→CREATE TABLE IF NOT EXISTS schema_metadata (
    30→    key TEXT PRIMARY KEY,
    31→    value TEXT NOT NULL
    32→) WITHOUT ROWID;
    33→
    34→-- ============================================================================
    35→-- CORE TABLES
    36→-- ============================================================================
    37→
    38→-- Project Tasks (replaces features.json)
    39→CREATE TABLE IF NOT EXISTS project_tasks (
    40→    id TEXT PRIMARY KEY CHECK(length(id) = 26),
    41→    title TEXT NOT NULL,
    42→    description TEXT,
    43→    status TEXT NOT NULL DEFAULT 'BACKLOG'
    44→        CHECK(status IN ('BACKLOG', 'TODO', 'DOING', 'REVIEW', 'QA', 'DONE')),
    45→    category TEXT,
    46→    sort_order REAL NOT NULL DEFAULT 0.0,
    47→    is_passed TEXT NOT NULL DEFAULT 'false'
    48→        CHECK(is_passed IN ('true', 'false')),
    49→    created_at TEXT NOT NULL,
    50→    updated_at TEXT NOT NULL
    51→);
    52→
    53→-- Task Steps (checklist items within a task)
    54→-- ID format: task#{task_ulid}#{step_ulid}
    55→CREATE TABLE IF NOT EXISTS task_steps (
    56→    id TEXT PRIMARY KEY,
    57→    description TEXT NOT NULL,
    58→    is_completed TEXT NOT NULL DEFAULT 'false'
    59→        CHECK(is_completed IN ('true', 'false')),
    60→    created_at TEXT NOT NULL
    61→) WITHOUT ROWID;
    62→
    63→-- Work Sessions (AI/human work periods)
    64→CREATE TABLE IF NOT EXISTS work_sessions (
    65→    id TEXT PRIMARY KEY CHECK(length(id) = 26),
    66→    summary TEXT,
    67→    started_at TEXT NOT NULL,
    68→    ended_at TEXT
    69→);
    70→
    71→-- Project Progress (session log entries)
    72→-- ID format: session#{session_ulid}#{progress_ulid}
    73→-- Note: No WITHOUT ROWID - needs implicit rowid for FTS5 sync
    74→CREATE TABLE IF NOT EXISTS project_progress (
    75→    id TEXT PRIMARY KEY,
    76→    content TEXT NOT NULL,
    77→    created_at TEXT NOT NULL
    78→);
    79→
    80→-- ============================================================================
    81→-- INDEXES
    82→-- ============================================================================
    83→
    84→CREATE INDEX IF NOT EXISTS idx_project_tasks_status ON project_tasks(status);
    85→CREATE INDEX IF NOT EXISTS idx_project_tasks_sort_order ON project_tasks(sort_order);
    86→CREATE INDEX IF NOT EXISTS idx_project_tasks_created_at ON project_tasks(created_at);
    87→CREATE INDEX IF NOT EXISTS idx_work_sessions_started_at ON work_sessions(started_at);
    88→"#;
    89→
    90→/// FTS5 virtual tables for full-text search.
    91→pub const FTS5_SCHEMA_SQL: &str = r#"
    92→-- ============================================================================
    93→-- FULL-TEXT SEARCH (FTS5)
    94→-- ============================================================================
    95→
    96→CREATE VIRTUAL TABLE IF NOT EXISTS project_tasks_fts USING fts5(
    97→    title,
    98→    description,
    99→    category,
   100→    content='project_tasks',
   101→    content_rowid='rowid'
   102→);
   103→
   104→CREATE VIRTUAL TABLE IF NOT EXISTS project_progress_fts USING fts5(
   105→    content,
   106→    content='project_progress',
   107→    content_rowid='rowid'
   108→);
   109→"#;
   110→
   111→/// Triggers to keep FTS5 tables in sync with source tables.
   112→pub const FTS5_TRIGGERS_SQL: &str = r#"
   113→-- ============================================================================
   114→-- FTS SYNC TRIGGERS: project_tasks
   115→-- ============================================================================
   116→
   117→CREATE TRIGGER IF NOT EXISTS project_tasks_fts_insert AFTER INSERT ON project_tasks BEGIN
   118→    INSERT INTO project_tasks_fts(rowid, title, description, category)
   119→    VALUES (NEW.rowid, NEW.title, NEW.description, NEW.category);
   120→END;
   121→
   122→CREATE TRIGGER IF NOT EXISTS project_tasks_fts_delete AFTER DELETE ON project_tasks BEGIN
   123→    INSERT INTO project_tasks_fts(project_tasks_fts, rowid, title, description, category)
   124→    VALUES('delete', OLD.rowid, OLD.title, OLD.description, OLD.category);
   125→END;
   126→
   127→CREATE TRIGGER IF NOT EXISTS project_tasks_fts_update AFTER UPDATE ON project_tasks BEGIN
   128→    INSERT INTO project_tasks_fts(project_tasks_fts, rowid, title, description, category)
   129→    VALUES('delete', OLD.rowid, OLD.title, OLD.description, OLD.category);
   130→    INSERT INTO project_tasks_fts(rowid, title, description, category)
   131→    VALUES (NEW.rowid, NEW.title, NEW.description, NEW.category);
   132→END;
   133→
   134→-- ============================================================================
   135→-- FTS SYNC TRIGGERS: project_progress
   136→-- ============================================================================
   137→
   138→CREATE TRIGGER IF NOT EXISTS project_progress_fts_insert AFTER INSERT ON project_progress BEGIN
   139→    INSERT INTO project_progress_fts(rowid, content)
   140→    VALUES (NEW.rowid, NEW.content);
   141→END;
   142→
   143→CREATE TRIGGER IF NOT EXISTS project_progress_fts_delete AFTER DELETE ON project_progress BEGIN
   144→    INSERT INTO project_progress_fts(project_progress_fts, rowid, content)
   145→    VALUES('delete', OLD.rowid, OLD.content);
   146→END;
   147→
   148→CREATE TRIGGER IF NOT EXISTS project_progress_fts_update AFTER UPDATE ON project_progress BEGIN
   149→    INSERT INTO project_progress_fts(project_progress_fts, rowid, content)
   150→    VALUES('delete', OLD.rowid, OLD.content);
   151→    INSERT INTO project_progress_fts(rowid, content)
   152→    VALUES (NEW.rowid, NEW.content);
   153→END;
   154→"#;
   155→
   156→/// Initialize database schema.
   157→///
   158→/// Creates all tables, indexes, FTS5 virtual tables, and triggers.
   159→/// Safe to call multiple times (uses IF NOT EXISTS).
   160→pub fn init_schema(conn: &Connection) -> DbResult<()> {
   161→    // Execute pragmas
   162→    conn.execute_batch(PRAGMAS)?;
   163→
   164→    // Create core tables and indexes
   165→    conn.execute_batch(SCHEMA_SQL)?;
   166→
   167→    // Create FTS5 virtual tables
   168→    conn.execute_batch(FTS5_SCHEMA_SQL)?;
   169→
   170→    // Create FTS sync triggers
   171→    conn.execute_batch(FTS5_TRIGGERS_SQL)?;
   172→
   173→    // Insert or update schema version
   174→    conn.execute(
   175→        "INSERT OR REPLACE INTO schema_metadata (key, value) VALUES ('version', ?1)",
   176→        [SCHEMA_VERSION],
   177→    )?;
   178→
   179→    Ok(())
   180→}
   181→
   182→/// Get the current schema version from the database.
   183→pub fn get_schema_version(conn: &Connection) -> DbResult<Option<String>> {
   184→    let result = conn.query_row(
   185→        "SELECT value FROM schema_metadata WHERE key = 'version'",
   186→        [],
   187→        |row| row.get::<_, String>(0),
   188→    );
   189→
   190→    match result {
   191→        Ok(version) => Ok(Some(version)),
   192→        Err(rusqlite::Error::QueryReturnedNoRows) => Ok(None),
   193→        Err(e) => Err(e.into()),
   194→    }
   195→}
   196→
   197→/// Check if schema is initialized.
   198→pub fn is_initialized(conn: &Connection) -> bool {
   199→    get_schema_version(conn).unwrap_or(None).is_some()
   200→}
   201→
   202→/// Get list of all tables in the database.
   203→pub fn list_tables(conn: &Connection) -> DbResult<Vec<String>> {
   204→    let mut stmt = conn.prepare(
   205→        "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name",
   206→    )?;
   207→
   208→    let tables = stmt
   209→        .query_map([], |row| row.get::<_, String>(0))?
   210→        .collect::<Result<Vec<_>, _>>()?;
   211→
   212→    Ok(tables)
   213→}
   214→
   215→/// Get list of all indexes in the database.
   216→pub fn list_indexes(conn: &Connection) -> DbResult<Vec<String>> {
   217→    let mut stmt = conn.prepare(
   218→        "SELECT name FROM sqlite_master WHERE type='index' AND name NOT LIKE 'sqlite_%' ORDER BY name",
   219→    )?;
   220→
   221→    let indexes = stmt
   222→        .query_map([], |row| row.get::<_, String>(0))?
   223→        .collect::<Result<Vec<_>, _>>()?;
   224→
   225→    Ok(indexes)
   226→}
   227→
   228→/// Get list of all triggers in the database.
   229→pub fn list_triggers(conn: &Connection) -> DbResult<Vec<String>> {
   230→    let mut stmt = conn.prepare(
   231→        "SELECT name FROM sqlite_master WHERE type='trigger' ORDER BY name",
   232→    )?;
   233→
   234→    let triggers = stmt
   235→        .query_map([], |row| row.get::<_, String>(0))?
   236→        .collect::<Result<Vec<_>, _>>()?;
   237→
   238→    Ok(triggers)
   239→}
