                [],
                |row| row.get(0),
            )
            .expect("Failed to search FTS");

        assert_eq!(count, 1);
    }

    // -------------------------------------------------------------------------
    // Default value tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_project_tasks_default_values() {
        let conn = create_test_db();
        init_schema(&conn).expect("Failed to initialize schema");

        // Insert with minimal fields
        conn.execute(
            "INSERT INTO project_tasks (id, title, created_at, updated_at)
             VALUES ('01ARZ3NDEKTSV4RRFFQ69G5FAV', 'Task', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Failed to insert task");

        // Check defaults
        let (status, sort_order, is_passed): (String, f64, String) = conn
            .query_row(
                "SELECT status, sort_order, is_passed FROM project_tasks WHERE id = '01ARZ3NDEKTSV4RRFFQ69G5FAV'",
                [],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)),
            )
            .expect("Failed to query task");

        assert_eq!(status, "BACKLOG");
        assert_eq!(sort_order, 0.0);
        assert_eq!(is_passed, "false");
    }

    #[test]
    fn test_task_steps_default_values() {
        let conn = create_test_db();
        init_schema(&conn).expect("Failed to initialize schema");

        // Insert with minimal fields
        conn.execute(
            "INSERT INTO task_steps (id, description, created_at)
             VALUES ('task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV', 'Step', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Failed to insert step");

        // Check defaults
        let is_completed: String = conn
            .query_row(
                "SELECT is_completed FROM task_steps WHERE id = 'task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV'",
                [],
                |row| row.get(0),
            )
            .expect("Failed to query step");

        assert_eq!(is_completed, "false");
    }
}

