   233→
   234→/// Update progress content.
   235→pub fn update_progress_content(conn: &Connection, id: &str, content: &str) -> DbResult<bool> {
   236→    let rows_affected = conn.execute(
   237→        "UPDATE project_progress SET content = ?1 WHERE id = ?2",
   238→        params![content, id],
   239→    )?;
   240→    Ok(rows_affected > 0)
   241→}
   242→
   243→// =============================================================================
   244→// DELETE
   245→// =============================================================================
   246→
   247→/// Delete a progress entry by ID.
   248→pub fn delete_progress(conn: &Connection, id: &str) -> DbResult<bool> {
   249→    let rows_affected = conn.execute("DELETE FROM project_progress WHERE id = ?1", [id])?;
   250→    Ok(rows_affected > 0)
   251→}
   252→
   253→/// Delete all progress entries for a session.
   254→pub fn delete_progress_for_session(conn: &Connection, session_id: &str) -> DbResult<i64> {
   255→    let pattern = ProjectProgress::glob_pattern(session_id);
