   243→        WHERE project_tasks_fts MATCH ?1
   244→        ORDER BY rank
   245→        LIMIT ?2
   246→        "#,
   247→    )?;
   248→
   249→    let rows = stmt.query_map(params![query, limit as i64], |row| row_to_task(row))?;
   250→
   251→    let mut tasks = Vec::new();
   252→    for row in rows {
   253→        tasks.push(row?);
   254→    }
   255→
   256→    Ok(tasks)
   257→}
   258→
   259→/// Count tasks by status.
   260→pub fn count_tasks_by_status(conn: &Connection) -> DbResult<std::collections::HashMap<String, i64>> {
   261→    let mut stmt = conn.prepare(
   262→        "SELECT status, COUNT(*) FROM project_tasks GROUP BY status",
   263→    )?;
   264→
   265→    let rows = stmt.query_map([], |row| {
   266→        Ok((row.get::<_, String>(0)?, row.get::<_, i64>(1)?))
   267→    })?;
   268→
   269→    let mut counts = std::collections::HashMap::new();
   270→    for row in rows {
   271→        let (status, count) = row?;
   272→        counts.insert(status, count);
   273→    }
   274→
   275→    Ok(counts)
   276→}
