   279→// UPDATE
   280→// =============================================================================
   281→
   282→/// Update fields for a task.
   283→#[derive(Default)]
   284→pub struct TaskUpdate {
   285→    pub title: Option<String>,
   286→    pub description: Option<Option<String>>,
   287→    pub status: Option<TaskStatus>,
   288→    pub category: Option<Option<String>>,
   289→    pub sort_order: Option<f64>,
   290→    pub is_passed: Option<bool>,
   291→}
   292→
   293→/// Update a task with the given changes.
   294→pub fn update_task(conn: &Connection, id: &str, update: TaskUpdate) -> DbResult<bool> {
   295→    let mut updates = Vec::new();
   296→    let mut values: Vec<Box<dyn rusqlite::ToSql>> = Vec::new();
   297→
   298→    if let Some(ref title) = update.title {
   299→        updates.push("title = ?");
   300→        values.push(Box::new(title.clone()));
   301→    }
   302→
   303→    if let Some(ref desc) = update.description {
   304→        updates.push("description = ?");
   305→        values.push(Box::new(desc.clone()));
   306→    }
   307→
   308→    if let Some(status) = update.status {
   309→        updates.push("status = ?");
   310→        values.push(Box::new(status.as_str().to_string()));
   311→    }
   312→
   313→    if let Some(ref category) = update.category {
   314→        updates.push("category = ?");
   315→        values.push(Box::new(category.clone()));
   316→    }
   317→
   318→    if let Some(sort_order) = update.sort_order {
   319→        updates.push("sort_order = ?");
   320→        values.push(Box::new(sort_order));
   321→    }
   322→
   323→    if let Some(is_passed) = update.is_passed {
   324→        updates.push("is_passed = ?");
   325→        values.push(Box::new(if is_passed { "true" } else { "false" }));
   326→    }
   327→
   328→    if updates.is_empty() {
   329→        return Ok(false);
   330→    }
   331→
   332→    // Always update updated_at
   333→    updates.push("updated_at = ?");
   334→    values.push(Box::new(Utc::now().to_rfc3339()));
   335→
   336→    // Add ID at the end
   337→    values.push(Box::new(id.to_string()));
   338→
   339→    let sql = format!(
   340→        "UPDATE project_tasks SET {} WHERE id = ?",
   341→        updates.join(", ")
   342→    );
   343→
   344→    let params: Vec<&dyn rusqlite::ToSql> = values.iter().map(|v| v.as_ref()).collect();
   345→    let rows_affected = conn.execute(&sql, params.as_slice())?;
   346→
   347→    Ok(rows_affected > 0)
   348→}
   349→
   350→/// Set task status.
   351→pub fn set_task_status(conn: &Connection, id: &str, status: TaskStatus) -> DbResult<bool> {
   352→    update_task(conn, id, TaskUpdate {
   353→        status: Some(status),
   354→        ..Default::default()
   355→    })
   356→}
   357→
   358→/// Set task as passed.
   359→pub fn set_task_passed(conn: &Connection, id: &str, passed: bool) -> DbResult<bool> {
   360→    update_task(conn, id, TaskUpdate {
   361→        is_passed: Some(passed),
   362→        ..Default::default()
   363→    })
   364→}
