   379→// REORDER
   380→// =============================================================================
   381→
   382→/// Get the sort order for positioning after another task.
   383→///
   384→/// If after_id is None, positions at the beginning.
   385→pub fn get_order_after(conn: &Connection, after_id: Option<&str>) -> DbResult<f64> {
   386→    if let Some(after_id) = after_id {
   387→        // Get the order of the after task
   388→        let after_order: f64 = conn.query_row(
   389→            "SELECT sort_order FROM project_tasks WHERE id = ?1",
   390→            [after_id],
   391→            |row| row.get(0),
   392→        )?;
   393→
   394→        // Get the next task's order (if any)
   395→        let next_order: Option<f64> = conn
   396→            .query_row(
   397→                "SELECT sort_order FROM project_tasks WHERE sort_order > ?1 ORDER BY sort_order ASC LIMIT 1",
   398→                [after_order],
   399→                |row| row.get(0),
   400→            )
   401→            .optional()?;
   402→
   403→        // Position between after and next
   404→        match next_order {
   405→            Some(next) => Ok((after_order + next) / 2.0),
   406→            None => Ok(after_order + 1.0),
   407→        }
   408→    } else {
   409→        // Position at the beginning
   410→        let min_order: Option<f64> = conn
   411→            .query_row(
   412→                "SELECT MIN(sort_order) FROM project_tasks",
   413→                [],
   414→                |row| row.get(0),
   415→            )
   416→            .optional()?
   417→            .flatten();
   418→
   419→        match min_order {
   420→            Some(min) => Ok(min - 1.0),
   421→            None => Ok(0.0),
   422→        }
   423→    }
   424→}
   425→
   426→/// Reorder a task to be after another task.
   427→pub fn reorder_task(conn: &Connection, id: &str, after_id: Option<&str>) -> DbResult<bool> {
   428→    let new_order = get_order_after(conn, after_id)?;
   429→    update_task(conn, id, TaskUpdate {
   430→        sort_order: Some(new_order),
   431→        ..Default::default()
   432→    })
   433→}
