   435→// =============================================================================
   436→// HELPERS
   437→// =============================================================================
   438→
   439→fn row_to_task(row: &rusqlite::Row) -> rusqlite::Result<ProjectTask> {
   440→    let status_str: String = row.get(3)?;
   441→    let is_passed_str: String = row.get(6)?;
   442→    let created_at_str: String = row.get(7)?;
   443→    let updated_at_str: String = row.get(8)?;
   444→
   445→    Ok(ProjectTask {
   446→        id: row.get(0)?,
   447→        title: row.get(1)?,
   448→        description: row.get(2)?,
   449→        status: TaskStatus::from_str(&status_str).unwrap_or_default(),
   450→        category: row.get(4)?,
   451→        sort_order: row.get(5)?,
   452→        is_passed: is_passed_str == "true",
   453→        created_at: chrono::DateTime::parse_from_rfc3339(&created_at_str)
   454→            .map(|dt| dt.with_timezone(&Utc))
   455→            .unwrap_or_else(|_| Utc::now()),
   456→        updated_at: chrono::DateTime::parse_from_rfc3339(&updated_at_str)
   457→            .map(|dt| dt.with_timezone(&Utc))
   458→            .unwrap_or_else(|_| Utc::now()),
   459→    })
   460→}
   461→
   462→pub(crate) fn encode_cursor(id: &str) -> String {
   463→    use std::io::Write;
   464→    let mut encoder = base64::write::EncoderStringWriter::new(&base64::engine::general_purpose::URL_SAFE_NO_PAD);
   465→    encoder.write_all(id.as_bytes()).unwrap();
   466→    encoder.into_inner()
   467→}
   468→
   469→pub(crate) fn decode_cursor(cursor: &str) -> DbResult<String> {
   470→    use base64::Engine;
   471→    let bytes = base64::engine::general_purpose::URL_SAFE_NO_PAD
   472→        .decode(cursor)
   473→        .map_err(|e| super::DbError::InvalidId(format!("Invalid cursor: {}", e)))?;
   474→    String::from_utf8(bytes)
   475→        .map_err(|e| super::DbError::InvalidId(format!("Invalid cursor UTF-8: {}", e)))
   476→}
